using Microsoft.EntityFrameworkCore;
using VetClinic.Data;

namespace VetClinic.Services;

public class AppointmentService(ApplicationDbContext db)
{
    public async Task<List<Appointment>> GetByDateAsync(DateTime date)
    {
        var start = date.Date;
        var end = start.AddDays(1);
        return await db.Appointments
            .Include(a => a.Patient)
            .Where(a => a.StartTime >= start && a.StartTime < end)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    public async Task<Appointment?> GetByIdAsync(int id)
    {
        return await db.Appointments
            .Include(a => a.Patient)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<bool> IsSlotAvailableAsync(string vetName, DateTime startTime, DateTime endTime, int? excludeId = null)
    {
        var query = db.Appointments
            .Where(a => a.VetName == vetName
                && a.Status != AppointmentStatus.Cancelled
                && a.StartTime < endTime
                && a.EndTime > startTime);

        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);

        return !await query.AnyAsync();
    }

    public async Task<Appointment?> CreateAsync(Appointment appointment)
    {
        if (!await IsSlotAvailableAsync(appointment.VetName, appointment.StartTime, appointment.EndTime))
            return null;

        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task<bool> RescheduleAsync(int id, DateTime newStart)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment == null) return false;

        var duration = appointment.EndTime - appointment.StartTime;
        var newEnd = newStart + duration;

        if (!await IsSlotAvailableAsync(appointment.VetName, newStart, newEnd, id))
            return false;

        appointment.StartTime = newStart;
        appointment.EndTime = newEnd;
        await db.SaveChangesAsync();
        return true;
    }

    public async Task CancelAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<int> GetTodayCountAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);
        return await db.Appointments
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled)
            .CountAsync();
    }
}

