@page "/patients"
@attribute [Authorize]

@inject PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Patients</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name or owner..."
               @oninput="OnSearch" value="@searchQuery" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-success" @onclick="() => showForm = !showForm">
            @(showForm ? "Cancel" : "Register New")
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Register New Patient</h5>
            <EditForm Model="newPatient" OnValidSubmit="CreatePatient" FormName="newPatientForm">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label>Pet Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.Name" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Species</label>
                        <InputText class="form-control" @bind-Value="newPatient.Species" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Breed</label>
                        <InputText class="form-control" @bind-Value="newPatient.Breed" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="newPatient.DateOfBirth" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Name</label>
                        <InputText class="form-control" @bind-Value="newPatient.OwnerName" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Phone</label>
                        <InputText class="form-control" @bind-Value="newPatient.OwnerPhone" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Email</label>
                        <InputText class="form-control" @bind-Value="newPatient.OwnerEmail" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Phone</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var p in patients)
        {
            <tr>
                <td><a href="patients/@p.Id">@p.Name</a></td>
                <td>@p.Species</td>
                <td>@p.Breed</td>
                <td>@p.OwnerName</td>
                <td>@p.OwnerPhone</td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Patient> patients = new();
    private string searchQuery = string.Empty;
    private bool showForm;
    private Patient newPatient = new() { DateOfBirth = DateTime.Today };

    protected override async Task OnInitializedAsync()
    {
        patients = await PatientService.GetAllAsync();
    }

    private async Task OnSearch(ChangeEventArgs e)
    {
        searchQuery = e.Value?.ToString() ?? string.Empty;
        patients = await PatientService.SearchAsync(searchQuery);
    }

    private async Task CreatePatient()
    {
        await PatientService.CreateAsync(newPatient);
        newPatient = new() { DateOfBirth = DateTime.Today };
        showForm = false;
        patients = await PatientService.SearchAsync(searchQuery);
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]

@inject PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Patient Detail</PageTitle>

@if (patient == null)
{
    <p>Loading...</p>
}
else
{
    <h1>@patient.Name</h1>

    <div class="card mb-4">
        <div class="card-body">
