            <EditForm Model="patient" OnValidSubmit="SavePatient" FormName="editPatientForm">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label>Pet Name</label>
                        <InputText class="form-control" @bind-Value="patient.Name" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Species</label>
                        <InputText class="form-control" @bind-Value="patient.Species" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Breed</label>
                        <InputText class="form-control" @bind-Value="patient.Breed" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="patient.DateOfBirth" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Name</label>
                        <InputText class="form-control" @bind-Value="patient.OwnerName" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Phone</label>
                        <InputText class="form-control" @bind-Value="patient.OwnerPhone" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Owner Email</label>
                        <InputText class="form-control" @bind-Value="patient.OwnerEmail" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save Changes</button>
            </EditForm>
            @if (saveMessage != null)
            {
                <div class="alert alert-success mt-2">@saveMessage</div>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5>Add Treatment Note</h5>
            <EditForm Model="newRecord" OnValidSubmit="AddRecord" FormName="addRecordForm">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label>Diagnosis</label>
                        <InputText class="form-control" @bind-Value="newRecord.Diagnosis" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Treatment</label>
                        <InputText class="form-control" @bind-Value="newRecord.Treatment" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Vet Name</label>
                        <InputText class="form-control" @bind-Value="newRecord.VetName" />
                    </div>
                    <div class="col-md-12 mb-2">
                        <label>Notes</label>
                        <InputTextArea class="form-control" @bind-Value="newRecord.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Add Record</button>
            </EditForm>
        </div>
    </div>

    <div class="card">
        <div class="card-body">
            <h5>Medical History</h5>
            @if (patient.MedicalRecords.Count == 0)
            {
                <p class="text-muted">No medical records yet.</p>
            }
            else
            {
                <table class="table">
                    <thead>
                        <tr>
                            <th>Date</th>
                            <th>Diagnosis</th>
                            <th>Treatment</th>
                            <th>Vet</th>
                            <th>Notes</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var r in patient.MedicalRecords)
                        {
                            <tr>
                                <td>@r.Date.ToShortDateString()</td>
                                <td>@r.Diagnosis</td>
                                <td>@r.Treatment</td>
                                <td>@r.VetName</td>
                                <td>@r.Notes</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Patient? patient;
    private MedicalRecord newRecord = new();
    private string? saveMessage;

    protected override async Task OnInitializedAsync()
    {
        patient = await PatientService.GetByIdAsync(Id);
    }

    private async Task SavePatient()
    {
        if (patient != null)
        {
            await PatientService.UpdateAsync(patient);
            saveMessage = "Saved successfully!";
        }
    }

    private async Task AddRecord()
    {
        if (patient != null)
        {
            newRecord.PatientId = patient.Id;
            await PatientService.AddMedicalRecordAsync(newRecord);
            newRecord = new();
            patient = await PatientService.GetByIdAsync(Id);
        }
    }
}

