@page "/appointments"
@attribute [Authorize]

@inject AppointmentService AppointmentService
@inject PatientService PatientService

<PageTitle>Appointments</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label>Select Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:event="onchange" @bind:after="LoadAppointments" />
    </div>
</div>

@if (selectedAppointment != null)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Appointment Details</h5>
            <p><strong>Patient:</strong> @selectedAppointment.Patient?.Name</p>
            <p><strong>Vet:</strong> @selectedAppointment.VetName</p>
            <p><strong>Reason:</strong> @selectedAppointment.Reason</p>
            <p><strong>Status:</strong> @selectedAppointment.Status</p>
            <p><strong>Notes:</strong> @selectedAppointment.Notes</p>

            @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
            {
                @if (showReschedule)
                {
                    <div class="row mb-2">
                        <div class="col-md-4">
                            <label>New Date & Time</label>
                            <input type="datetime-local" class="form-control" @bind="rescheduleDateTime" />
                        </div>
                        <div class="col-md-4 align-self-end">
                            <button class="btn btn-primary" @onclick="Reschedule">Confirm Reschedule</button>
                        </div>
                    </div>
                    @if (rescheduleError != null)
                    {
                        <div class="alert alert-danger">@rescheduleError</div>
                    }
                }
                else
                {
                    <button class="btn btn-warning me-2" @onclick="() => showReschedule = true">Reschedule</button>
                }
                <button class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
            }
            <button class="btn btn-secondary ms-2" @onclick="() => selectedAppointment = null">Close</button>
        </div>
    </div>
}

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Appointment at @createSlotTime.ToString("HH:mm")</h5>
            <EditForm Model="newAppointment" OnValidSubmit="CreateAppointment" FormName="createAppointmentForm">
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label>Patient</label>
                        <InputSelect class="form-control" @bind-Value="newAppointment.PatientId">
                            <option value="0">-- Select Patient --</option>
                            @foreach (var p in allPatients)
                            {
                                <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Vet Name</label>
                        <InputText class="form-control" @bind-Value="newAppointment.VetName" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label>Reason</label>
                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Book</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
            </EditForm>
            @if (createError != null)
            {
                <div class="alert alert-danger mt-2">@createError</div>
            }
        </div>
    </div>
}

<table class="table table-bordered">
    <thead>
        <tr>
            <th>Time</th>
            <th>Status</th>
            <th>Action</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var slot in timeSlots)
        {
            var appt = GetAppointmentForSlot(slot);
            <tr class="@(appt != null ? "table-info" : "")">
                <td>@slot.ToString("HH:mm") - @slot.AddMinutes(30).ToString("HH:mm")</td>
