+                        <InputText class="form-control" @bind-Value="newAppointment.VetName" />
+                    </div>
+                    <div class="col-md-4 mb-2">
+                        <label>Reason</label>
+                        <InputText class="form-control" @bind-Value="newAppointment.Reason" />
+                    </div>
+                </div>
+                <button type="submit" class="btn btn-primary">Book</button>
+                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
+            </EditForm>
+            @if (createError != null)
+            {
+                <div class="alert alert-danger mt-2">@createError</div>
+            }
+        </div>
+    </div>
+}
+
+<table class="table table-bordered">
+    <thead>
+        <tr>
+            <th>Time</th>
+            <th>Status</th>
+            <th>Action</th>
+        </tr>
+    </thead>
+    <tbody>
+        @foreach (var slot in timeSlots)
+        {
+            var appt = GetAppointmentForSlot(slot);
+            <tr class="@(appt != null ? "table-info" : "")">
+                <td>@slot.ToString("HH:mm") - @slot.AddMinutes(30).ToString("HH:mm")</td>
+                <td>
+                    @if (appt != null)
+                    {
+                        <span>@appt.Patient?.Name — @appt.VetName (@appt.Status)</span>
+                    }
+                    else
+                    {
+                        <span class="text-muted">Available</span>
+                    }
+                </td>
+                <td>
+                    @if (appt != null)
+                    {
+                        <button class="btn btn-sm btn-outline-primary" @onclick="() => SelectAppointment(appt)">Details</button>
+                    }
+                    else
+                    {
+                        <button class="btn btn-sm btn-outline-success" @onclick="() => OpenCreateForm(slot)">Book</button>
+                    }
+                </td>
+            </tr>
+        }
+    </tbody>
+</table>
+
+@code {
+    private DateTime selectedDate = DateTime.Today;
+    private List<Appointment> appointments = new();
+    private List<Patient> allPatients = new();
+    private List<DateTime> timeSlots = new();
+    private Appointment? selectedAppointment;
+    private bool showCreateForm;
+    private DateTime createSlotTime;
+    private Appointment newAppointment = new();
+    private string? createError;
+    private bool showReschedule;
+    private DateTime rescheduleDateTime = DateTime.Now;
+    private string? rescheduleError;
+
+    protected override async Task OnInitializedAsync()
+    {
+        GenerateTimeSlots();
+        await LoadAppointments();
+        allPatients = await PatientService.GetAllAsync();
+    }
+
+    private void GenerateTimeSlots()
+    {
+        timeSlots.Clear();
+        for (int hour = 8; hour < 18; hour++)
+        {
+            timeSlots.Add(selectedDate.Date.AddHours(hour));
+            timeSlots.Add(selectedDate.Date.AddHours(hour).AddMinutes(30));
+        }
+    }
+
+    private async Task LoadAppointments()
+    {
+        GenerateTimeSlots();
+        appointments = await AppointmentService.GetByDateAsync(selectedDate);
+        selectedAppointment = null;
+        showCreateForm = false;
+    }
+
+    private Appointment? GetAppointmentForSlot(DateTime slot)
+    {
+        return appointments.FirstOrDefault(a =>
+            a.Status != AppointmentStatus.Cancelled &&
+            a.StartTime <= slot && a.EndTime > slot);
+    }
+
+    private void SelectAppointment(Appointment appt)
+    {
+        selectedAppointment = appt;
+        showCreateForm = false;
+        showReschedule = false;
+        rescheduleError = null;
+    }
+
+    private void OpenCreateForm(DateTime slot)
+    {
+        createSlotTime = slot;
+        newAppointment = new Appointment
+        {
+            StartTime = slot,
+            EndTime = slot.AddMinutes(30)
+        };
+        showCreateForm = true;
+        selectedAppointment = null;
+        createError = null;
+    }
+
+    private async Task CreateAppointment()
+    {
+        if (newAppointment.PatientId == 0)
+        {
+            createError = "Please select a patient.";
+            return;
+        }
+        var result = await AppointmentService.CreateAsync(newAppointment);
+        if (result == null)
+        {
+            createError = "Slot not available for this vet.";
+            return;
+        }
+        showCreateForm = false;
+        createError = null;
+        await LoadAppointments();
+    }
+
+    private async Task Reschedule()
+    {
+        if (selectedAppointment == null) return;
+        var success = await AppointmentService.RescheduleAsync(selectedAppointment.Id, rescheduleDateTime);
+        if (!success)
+        {
+            rescheduleError = "Cannot reschedule — slot not available.";
+            return;
+        }
+        showReschedule = false;
+        rescheduleError = null;
+        await LoadAppointments();
+    }
+
+    private async Task CancelAppointment()
+    {
+        if (selectedAppointment == null) return;
+        await AppointmentService.CancelAsync(selectedAppointment.Id);
+        selectedAppointment = null;
+        await LoadAppointments();
+    }
+}
+

